     1→"use client";
     2→
     3→import useSWR from "swr";
     4→import Link from "next/link";
     5→import { useState, useRef, useEffect, useCallback } from "react";
     6→import { useRouter } from "next/navigation";
     7→import {
     8→  projects as projectsApi,
     9→  sources as sourcesApi,
    10→  contextSources as ctxApi,
    11→  agent as agentApi,
    12→  releases as releasesApi,
    13→} from "@/lib/api/client";
    14→import type { AgentRules, Source } from "@/lib/api/types";
    15→import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
    16→import { ConfirmDialog } from "@/components/ui/confirm-dialog";
    17→import { SourceForm } from "@/components/sources/source-form";
    18→import { NewContextSourceForm } from "@/components/context-sources/new-context-source-form";
    19→import { ProjectLogo } from "@/components/ui/project-logo";
    20→import { ProviderBadge } from "@/components/ui/provider-badge";
    21→import { StatusDot } from "@/components/ui/status-dot";
    22→import { SectionLabel } from "@/components/ui/section-label";
    23→import { formatInterval } from "@/lib/format";
    24→import { getPathSegment } from "@/lib/path";
    25→import { Pencil, Trash2, Play, Plus, ArrowLeft } from "lucide-react";
    26→
    27→/* ---------- Tabs ---------- */
    28→
    29→const tabs = [
    30→  { key: "sources", label: "Sources" },
    31→  { key: "context", label: "Context Sources" },
    32→  { key: "agent", label: "Semantic Release Settings" },
    33→] as const;
    34→
    35→type TabKey = (typeof tabs)[number]["key"];
    36→
    37→/* ---------- Helpers ---------- */
    38→
    39→function formatDuration(startedAt?: string, completedAt?: string): string {
    40→  if (!startedAt) return "--";
    41→  const start = new Date(startedAt).getTime();
    42→  const end = completedAt ? new Date(completedAt).getTime() : Date.now();
    43→  const secs = Math.round((end - start) / 1000);
    44→  if (secs < 60) return `${secs}s`;
    45→  const mins = Math.floor(secs / 60);
    46→  const rem = secs % 60;
    47→  return `${mins}m ${rem}s`;
    48→}
    49→
    50→function truncate(str: string, max: number): string {
    51→  return str.length > max ? str.slice(0, max) + "\u2026" : str;
    52→}
    53→
    54→/* ---------- Main component ---------- */
    55→
    56→export function ProjectDetail() {
    57→  // Read ID from URL path — useParams() returns stale "0" in static export
    58→  const id = getPathSegment(1); // /projects/{id}
    59→  const router = useRouter();
    60→  const [activeTab, setActiveTab] = useState<TabKey>("sources");
    61→
    62→  /* Test run state */
    63→  const [testSourceId, setTestSourceId] = useState<string>("");
    64→  const [testVersion, setTestVersion] = useState<string>("");
    65→  const [testRunning, setTestRunning] = useState(false);
    66→
    67→  /* Agent config local state */
    68→  const [promptDraft, setPromptDraft] = useState<string | null>(null);
    69→  const [rulesDraft, setRulesDraft] = useState<AgentRules | null>(null);
    70→  const [saving, setSaving] = useState(false);
    71→
    72→  /* Inline edit state */
    73→  const [editingName, setEditingName] = useState(false);
    74→  const [editingDesc, setEditingDesc] = useState(false);
    75→  const [nameDraft, setNameDraft] = useState("");
    76→  const [descDraft, setDescDraft] = useState("");
    77→  const nameRef = useRef<HTMLInputElement>(null);
    78→  const descRef = useRef<HTMLInputElement>(null);
    79→
    80→  /* Dialog state */
    81→  const [sourceCreateOpen, setSourceCreateOpen] = useState(false);
    82→  const [editingSource, setEditingSource] = useState<Source | null>(null);
    83→  const [deletingSourceId, setDeletingSourceId] = useState<string | null>(null);
    84→  const [ctxCreateOpen, setCtxCreateOpen] = useState(false);
    85→  const [deletingCtxId, setDeletingCtxId] = useState<string | null>(null);
    86→  const [deletingProject, setDeletingProject] = useState(false);
    87→
    88→  /* Data fetching */
    89→  const { data, isLoading, mutate: mutateProject } = useSWR(`project-${id}`, () => projectsApi.get(id));
    90→  const { data: sourcesData, mutate: mutateSources } = useSWR(
    91→    `project-${id}-sources`,
    92→    () => sourcesApi.listByProject(id),
    93→  );
    94→  const { data: ctxData, mutate: mutateCtx } = useSWR(
    95→    `project-${id}-ctx`,
    96→    () => ctxApi.list(id),
    97→  );
    98→  const { data: runsData, mutate: mutateRuns } = useSWR(
    99→    activeTab === "agent" ? `project-${id}-runs` : null,
   100→    () => agentApi.listRuns(id),
   101→  );
   102→  const { data: testReleasesData } = useSWR(
   103→    testSourceId ? `source-${testSourceId}-releases` : null,
   104→    () => releasesApi.listBySource(testSourceId, 1),
   105→  );
   106→
   107→  const saveName = useCallback(async () => {
   108→    const p = data?.data;
   109→    if (!p) return;
   110→    const trimmed = nameDraft.trim();
   111→    if (trimmed && trimmed !== p.name) {
   112→      await projectsApi.update(id, { name: trimmed, description: p.description });
   113→      mutateProject();
   114→    }
   115→    setEditingName(false);
   116→  }, [nameDraft, data, id, mutateProject]);
   117→
   118→  const saveDesc = useCallback(async () => {
   119→    const p = data?.data;
   120→    if (!p) return;
   121→    const trimmed = descDraft.trim();
   122→    if (trimmed !== (p.description ?? "")) {
   123→      await projectsApi.update(id, { name: p.name, description: trimmed || undefined });
   124→      mutateProject();
   125→    }
   126→    setEditingDesc(false);
   127→  }, [descDraft, data, id, mutateProject]);
   128→
   129→  /* Click-outside handlers */
   130→  useEffect(() => {
   131→    if (!editingName) return;
   132→    const handler = (e: MouseEvent) => {
   133→      if (nameRef.current && !nameRef.current.contains(e.target as Node)) saveName();
   134→    };
   135→    document.addEventListener("mousedown", handler);
   136→    return () => document.removeEventListener("mousedown", handler);
   137→  }, [editingName, saveName]);
   138→
   139→  useEffect(() => {
   140→    if (!editingDesc) return;
   141→    const handler = (e: MouseEvent) => {
   142→      if (descRef.current && !descRef.current.contains(e.target as Node)) saveDesc();
   143→    };
   144→    document.addEventListener("mousedown", handler);
   145→    return () => document.removeEventListener("mousedown", handler);
   146→  }, [editingDesc, saveDesc]);
   147→
   148→  /* Handlers */
   149→  const handleToggleSource = async (source: { id: string; provider: string; repository: string; poll_interval_seconds: number; enabled: boolean; config?: Record<string, unknown> }) => {
   150→    await sourcesApi.update(source.id, {
   151→      provider: source.provider,
   152→      repository: source.repository,
   153→      poll_interval_seconds: source.poll_interval_seconds,
   154→      enabled: !source.enabled,
   155→      config: source.config,
   156→    });
   157→    mutateSources();
   158→  };
   159→
   160→  const handleSaveAgentConfig = async () => {
   161→    if (!project) return;
   162→    setSaving(true);
   163→    try {
   164→      const input = {
   165→        name: project.name,
   166→        description: project.description,
   167→        agent_prompt: promptDraft ?? project.agent_prompt,
   168→        agent_rules: rulesDraft ?? project.agent_rules,
   169→      };
   170→      await projectsApi.update(id, input);
   171→      mutateProject();
   172→      setPromptDraft(null);
   173→      setRulesDraft(null);
   174→    } finally {
   175→      setSaving(false);
   176→    }
   177→  };
   178→
   179→  const handleTestRun = async () => {
   180→    if (!testVersion) return;
   181→    setTestRunning(true);
   182→    try {
   183→      await agentApi.triggerRun(id, testVersion);
   184→      mutateRuns();
   185→    } finally {
   186→      setTestRunning(false);
   187→    }
   188→  };
   189→
   190→  /* Loading / not found states */
   191→  if (isLoading) {
   192→    return (
   193→      <div className="flex h-48 items-center justify-center" style={{ color: "#9ca3af" }}>
   194→        Loading...
   195→      </div>
   196→    );
   197→  }
   198→
   199→  const project = data?.data;
   200→  if (!project) {
   201→    return (
   202→      <div className="flex h-48 items-center justify-center" style={{ color: "#6b7280" }}>
   203→        Project not found
   204→      </div>
   205→    );
   206→  }
   207→
   208→  /* Derived counts */
   209→  const sourceCount = sourcesData?.data?.length;
   210→  const ctxCount = ctxData?.data?.length;
   211→
   212→  /* Current effective values */
   213→  const currentPrompt = promptDraft ?? project.agent_prompt ?? "";
   214→  const currentRules: AgentRules = rulesDraft ?? project.agent_rules ?? {};
   215→
   216→  return (
   217→    <div className="space-y-0">
   218→      {/* ===== Header zone ===== */}
   219→      <div
   220→        className="-m-6 mb-0 border-b px-6 py-5"
   221→        style={{ backgroundColor: "#ffffff", borderColor: "#e8e8e5" }}
   222→      >
   223→        {/* Back link */}
   224→        <Link
   225→          href="/projects"
   226→          className="mb-4 inline-flex items-center gap-1.5 transition-colors hover:opacity-70"
   227→          style={{
   228→            fontFamily: "var(--font-dm-sans)",
   229→            fontSize: "13px",
   230→            color: "#6b7280",
   231→          }}
   232→        >
   233→          <ArrowLeft size={14} />
   234→          Back to Projects
   235→        </Link>
   236→        <div className="flex items-start justify-between">
   237→          {/* Left: project info */}
   238→          <div className="min-w-0 flex-1 flex items-start gap-4">
   239→            <ProjectLogo name={project.name} sources={sourcesData?.data} size={48} />
   240→            <div className="min-w-0 flex-1">
   241→            {editingName ? (
   242→              <input
   243→                ref={nameRef}
   244→                value={nameDraft}
   245→                onChange={(e) => setNameDraft(e.target.value)}
   246→                onKeyDown={(e) => {
   247→                  if (e.key === "Enter") saveName();
   248→                  if (e.key === "Escape") setEditingName(false);
   249→                }}
   250→                autoFocus
   251→                className="w-full max-w-md rounded-md border px-2 py-1 text-[28px] font-bold leading-tight focus:outline-none focus:ring-1"
   252→                style={{
   253→                  fontFamily: "var(--font-fraunces), serif",
   254→                  borderColor: "#e8e8e5",
   255→                  color: "#111113",
   256→                }}
   257→              />
   258→            ) : (
   259→              <h1
   260→                className="group flex cursor-pointer items-center gap-2 text-[28px] font-bold leading-tight"
   261→                style={{ fontFamily: "var(--font-fraunces), serif" }}
   262→                onClick={() => {
   263→                  setNameDraft(project.name);
   264→                  setEditingName(true);
   265→                }}
   266→              >
   267→                {project.name}
   268→                <Pencil className="h-4 w-4 shrink-0 opacity-0 transition-opacity group-hover:opacity-40" />
   269→              </h1>
   270→            )}
   271→            {editingDesc ? (
   272→              <input
   273→                ref={descRef}
   274→                value={descDraft}
   275→                onChange={(e) => setDescDraft(e.target.value)}
   276→                onKeyDown={(e) => {
   277→                  if (e.key === "Enter") saveDesc();
   278→                  if (e.key === "Escape") setEditingDesc(false);
   279→                }}
   280→                autoFocus
   281→                placeholder="Add a description..."
   282→                className="mt-1 w-full max-w-lg rounded-md border px-2 py-1 text-[14px] focus:outline-none focus:ring-1"
   283→                style={{
   284→                  fontFamily: "var(--font-dm-sans), sans-serif",
   285→                  borderColor: "#e8e8e5",
   286→                  color: "#6b7280",
   287→                }}
   288→              />
   289→            ) : (
   290→              <p
   291→                className="group mt-1 flex cursor-pointer items-center gap-2 text-[14px]"
   292→                style={{ fontFamily: "var(--font-dm-sans), sans-serif", color: "#6b7280" }}
   293→                onClick={() => {
   294→                  setDescDraft(project.description ?? "");
   295→                  setEditingDesc(true);
   296→                }}
   297→              >
   298→                {project.description || "Add a description..."}
   299→                <Pencil className="h-3 w-3 shrink-0 opacity-0 transition-opacity group-hover:opacity-40" />
   300→              </p>
   301→            )}
   302→            <p
   303→              className="mt-2 text-[12px]"
   304→              style={{ fontFamily: "var(--font-dm-sans), sans-serif", color: "#9ca3af" }}
   305→            >
   306→              {sourceCount !== undefined ? `${sourceCount} sources` : "-- sources"}
   307→              {" \u00B7 "}
   308→              {ctxCount !== undefined ? `${ctxCount} context sources` : "-- context sources"}
   309→            </p>
   310→            </div>
   311→          </div>
   312→
   313→          {/* Right: actions */}
   314→          <div className="flex shrink-0 items-center gap-2 ml-4">
   315→            <button
   316→              onClick={() => setDeletingProject(true)}
   317→              className="inline-flex items-center gap-1.5 rounded-md border px-3 py-1.5 text-[13px] font-medium transition-colors hover:bg-red-50"
   318→              style={{
   319→                fontFamily: "var(--font-dm-sans), sans-serif",
   320→                borderColor: "#dc2626",
   321→                color: "#dc2626",
   322→              }}
   323→            >
   324→              <Trash2 className="h-3.5 w-3.5" />
   325→              Delete
   326→            </button>
   327→          </div>
   328→        </div>
   329→      </div>
   330→
   331→      {/* ===== Tab bar ===== */}
   332→      <div
   333→        className="-mx-6 border-b px-6"
   334→        style={{ borderColor: "#e8e8e5", backgroundColor: "#ffffff" }}
   335→      >
   336→        <div className="flex gap-0">
   337→          {tabs.map((tab) => {
   338→            const isActive = activeTab === tab.key;
   339→            return (
   340→              <button
   341→                key={tab.key}
   342→                onClick={() => setActiveTab(tab.key)}
   343→                className="relative px-4 py-2.5 text-[13px] font-medium transition-colors"
   344→                style={{
   345→                  fontFamily: "var(--font-dm-sans), sans-serif",
   346→                  color: isActive ? "#111113" : "#9ca3af",
   347→                }}
   348→              >
   349→                {tab.label}
   350→                {isActive && (
   351→                  <span
   352→                    className="absolute bottom-0 left-4 right-4 h-[2px]"
   353→                    style={{ backgroundColor: "#e8601a" }}
   354→                  />
   355→                )}
   356→              </button>
   357→            );
   358→          })}
   359→        </div>
   360→      </div>
   361→
   362→      {/* ===== Tab content ===== */}
   363→      <div className="pt-6">
   364→        {/* --- Sources tab --- */}
   365→        {activeTab === "sources" && (
   366→          <div>
   367→            <div className="mb-4 flex items-center justify-between">
   368→              <SectionLabel>Sources</SectionLabel>
   369→              <button
   370→                onClick={() => setSourceCreateOpen(true)}
   371→                className="inline-flex items-center gap-1.5 rounded-md border px-3 py-1.5 text-[13px] font-medium transition-colors hover:bg-[#f3f3f1]"
   372→                style={{
   373→                  fontFamily: "var(--font-dm-sans), sans-serif",
   374→                  borderColor: "#e8e8e5",
   375→                  color: "#374151",
   376→                }}
   377→              >
   378→                <Plus className="h-3.5 w-3.5" />
   379→                Add Source
   380→              </button>
   381→            </div>
   382→
   383→            {sourcesData?.data && sourcesData.data.length > 0 ? (
   384→              <div className="overflow-hidden rounded-md border" style={{ borderColor: "#e8e8e5" }}>
   385→                <table className="w-full text-[13px]" style={{ fontFamily: "var(--font-dm-sans), sans-serif" }}>
   386→                  <thead>
   387→                    <tr style={{ backgroundColor: "#fafaf9" }}>
   388→                      <th className="px-4 py-2 text-left text-[11px] font-medium uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>Provider</th>
   389→                      <th className="px-4 py-2 text-left text-[11px] font-medium uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>Repository</th>
   390→                      <th className="px-4 py-2 text-left text-[11px] font-medium uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>Interval</th>
   391→                      <th className="px-4 py-2 text-left text-[11px] font-medium uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>Status</th>
   392→                      <th className="px-4 py-2 text-left text-[11px] font-medium uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>Last polled</th>
   393→                      <th className="px-4 py-2 text-right text-[11px] font-medium uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}></th>
   394→                    </tr>
   395→                  </thead>
   396→                  <tbody>
   397→                    {sourcesData.data.map((source) => (
   398→                      <tr key={source.id} className="border-t" style={{ borderColor: "#e8e8e5" }}>
   399→                        <td className="px-4 py-3">
   400→                          <ProviderBadge provider={source.provider} />
   401→                        </td>
   402→                        <td className="px-4 py-3">
   403→                          <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "12px" }}>
   404→                            {source.repository}
   405→                          </span>
   406→                        </td>
   407→                        <td className="px-4 py-3" style={{ color: "#6b7280" }}>
   408→                          {formatInterval(source.poll_interval_seconds)}
   409→                        </td>
   410→                        <td className="px-4 py-3">
   411→                          <button
   412→                            onClick={() => handleToggleSource(source)}
   413→                            className="relative inline-flex h-5 w-9 shrink-0 cursor-pointer items-center rounded-full transition-colors duration-200"
   414→                            style={{ backgroundColor: source.enabled ? "#16a34a" : "#d1d5db" }}
   415→                            title={source.enabled ? "Disable polling" : "Enable polling"}
   416→                          >
   417→                            <span
   418→                              className="inline-block h-3.5 w-3.5 rounded-full bg-white shadow transition-transform duration-200"
   419→                              style={{ transform: source.enabled ? "translateX(18px)" : "translateX(3px)" }}
   420→                            />
   421→                          </button>
   422→                        </td>
   423→                        <td className="px-4 py-3" style={{ color: "#9ca3af" }}>
   424→                          {source.last_polled_at
   425→                            ? new Date(source.last_polled_at).toLocaleString()
   426→                            : "Never"}
   427→                        </td>
   428→                        <td className="px-4 py-3 text-right">
   429→                          <div className="flex items-center justify-end gap-2">
   430→                            <button
   431→                              onClick={() => setEditingSource(source)}
   432→                              className="rounded p-1 text-[#9ca3af] transition-colors hover:bg-[#f3f3f1] hover:text-[#111113]"
   433→                              title="Edit source"
   434→                            >
   435→                              <Pencil className="h-4 w-4" />
   436→                            </button>
   437→                            <button
   438→                              onClick={() => setDeletingSourceId(source.id)}
   439→                              className="rounded p-1 text-[#9ca3af] transition-colors hover:bg-red-50 hover:text-red-600"
   440→                              title="Delete source"
   441→                            >
   442→                              <Trash2 className="h-4 w-4" />
   443→                            </button>
   444→                          </div>
   445→                        </td>
   446→                      </tr>
   447→                    ))}
   448→                  </tbody>
   449→                </table>
   450→              </div>
   451→            ) : (
   452→              <div
   453→                className="flex h-32 items-center justify-center rounded-md border text-[13px]"
   454→                style={{ borderColor: "#e8e8e5", color: "#9ca3af" }}
   455→              >
   456→                No sources configured
   457→              </div>
   458→            )}
   459→          </div>
   460→        )}
   461→
   462→        {/* --- Context Sources tab --- */}
   463→        {activeTab === "context" && (
   464→          <div>
   465→            <div className="mb-4 flex items-center justify-between">
   466→              <SectionLabel>Context Sources</SectionLabel>
   467→              <button
   468→                onClick={() => setCtxCreateOpen(true)}
   469→                className="inline-flex items-center gap-1.5 rounded-md border px-3 py-1.5 text-[13px] font-medium transition-colors hover:bg-[#f3f3f1]"
   470→                style={{
   471→                  fontFamily: "var(--font-dm-sans), sans-serif",
   472→                  borderColor: "#e8e8e5",
   473→                  color: "#374151",
   474→                }}
   475→              >
   476→                <Plus className="h-3.5 w-3.5" />
   477→                Add Context Source
   478→              </button>
   479→            </div>
   480→
   481→            {ctxData?.data && ctxData.data.length > 0 ? (
   482→              <div className="overflow-hidden rounded-md border" style={{ borderColor: "#e8e8e5" }}>
   483→                <table className="w-full text-[13px]" style={{ fontFamily: "var(--font-dm-sans), sans-serif" }}>
   484→                  <thead>
   485→                    <tr style={{ backgroundColor: "#fafaf9" }}>
   486→                      <th className="px-4 py-2 text-left text-[11px] font-medium uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>Type</th>
   487→                      <th className="px-4 py-2 text-left text-[11px] font-medium uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>Name</th>
   488→                      <th className="px-4 py-2 text-left text-[11px] font-medium uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>Config URL</th>
   489→                      <th className="px-4 py-2 text-right text-[11px] font-medium uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}></th>
   490→                    </tr>
   491→                  </thead>
   492→                  <tbody>
   493→                    {ctxData.data.map((ctx) => (
   494→                      <tr key={ctx.id} className="border-t" style={{ borderColor: "#e8e8e5" }}>
   495→                        <td className="px-4 py-3">
   496→                          <span
   497→                            className="inline-flex items-center rounded-full px-2 py-0.5 text-[11px] font-medium leading-none"
   498→                            style={{ backgroundColor: "#f3f3f1", color: "#374151" }}
   499→                          >
   500→                            {ctx.type}
   501→                          </span>
   502→                        </td>
   503→                        <td className="px-4 py-3 font-medium" style={{ color: "#111113" }}>
   504→                          {ctx.name}
   505→                        </td>
   506→                        <td className="px-4 py-3" style={{ color: "#9ca3af" }}>
   507→                          <span
   508→                            className="text-[12px]"
   509→                            style={{ fontFamily: "'JetBrains Mono', monospace" }}
   510→                            title={typeof ctx.config?.url === "string" ? ctx.config.url : ""}
