   448→/* ---------- Compact Row ---------- */
   449→
   450→function ProjectCompactRow({ project }: { project: Project }) {
   451→  const { data: relData } = useSWR(`project-${project.id}-card-releases`, () =>
   452→    releasesApi.listByProject(project.id, 1, 5)
   453→  );
   454→  const { data: srcData } = useSWR(`project-${project.id}-card-sources`, () =>
   455→    sourcesApi.listByProject(project.id)
   456→  );
   457→  const { data: srData } = useSWR(`project-${project.id}-card-sr`, () =>
