   468→  for (const s of sources) sourceMap.set(s.id, s);
   469→
   470→  const latestSrc = latest ? sourceMap.get(latest.source_id) : undefined;
   471→  const latestIcon = latestSrc ? getProviderIcon(latestSrc.provider) : undefined;
   472→
   473→  const urgencyStyle = latestSr?.report?.urgency
   474→    ? URGENCY_COLORS[latestSr.report.urgency.toLowerCase()]
   475→    : undefined;
   476→
   477→  return (
   478→    <Link
