   517→        {latestSr ? (
   518→          <>
   519→            <span
   520→              className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none shrink-0"
   521→              style={{
   522→                backgroundColor: "#eff6ff",
   523→                fontFamily: "'JetBrains Mono', monospace",
   524→                color: "#1d4ed8",
   525→              }}
   526→            >
   527→              {latestSr.version}
   528→            </span>
   529→            {urgencyStyle && (
   530→              <span
   531→                className="inline-flex items-center rounded-full px-1.5 py-0.5 text-[10px] font-medium leading-none shrink-0"
   532→                style={{ backgroundColor: urgencyStyle.bg, color: urgencyStyle.text }}
   533→              >
   534→                {latestSr.report?.urgency}
   535→              </span>
   536→            )}
   537→            {latestSr.report?.summary && (
   538→              <span className="text-[11px] truncate" style={{ color: "#9ca3af" }}>
   539→                {latestSr.report.summary.length > 60
   540→                  ? latestSr.report.summary.slice(0, 60) + "\u2026"
   541→                  : latestSr.report.summary}
   542→              </span>
   543→            )}
   544→          </>
   545→        ) : (
   546→          <span className="text-[12px] italic" style={{ color: "#c4c4c0" }}>
   547→            No analysis
   548→          </span>
   549→        )}
   550→      </span>
   551→
   552→      {/* Arrow */}
   553→      <ArrowRight className="h-3.5 w-3.5 shrink-0" style={{ color: "#c4c4c0" }} />
   554→    </Link>
   555→  );
