    28→function getRiskColors(riskLevel?: string) {
    29→  switch (riskLevel?.toUpperCase()) {
    30→    case "CRITICAL":
    31→      return { border: "#dc2626", bg: "#fff1f2", text: "#991b1b" };
    32→    case "HIGH":
    33→      return { border: "#d97706", bg: "#fff8f0", text: "#92400e" };
    34→    case "MEDIUM":
    35→      return { border: "#ca8a04", bg: "#fefce8", text: "#854d0e" };
    36→    case "LOW":
    37→    default:
    38→      return { border: "#16a34a", bg: "#f0fdf4", text: "#166534" };
    39→  }
    40→}
    41→
    42→function safeHostname(url: string): string {
    43→  try {
    44→    return new URL(url).hostname.replace("www.", "");
    45→  } catch {
    46→    return url;
    47→  }
    48→}
    49→
    50→function getDownloadLabel(url: string): { label: string; isDirect: boolean } {
    51→  const lower = url.toLowerCase();
    52→  const filename = lower.split("/").pop() ?? "";
    53→
    54→  // Detect platform from common patterns in the URL or filename
    55→  const platforms: [RegExp, string][] = [
    56→    [/linux.*amd64|amd64.*linux/, "Linux x64"],
    57→    [/linux.*arm64|arm64.*linux|linux.*aarch64/, "Linux ARM64"],
    58→    [/linux.*386|linux.*i386/, "Linux x86"],
    59→    [/darwin.*arm64|arm64.*darwin|macos.*arm64|osx.*arm64/, "macOS ARM64"],
    60→    [/darwin.*amd64|amd64.*darwin|macos.*amd64|osx.*amd64/, "macOS x64"],
    61→    [/darwin|macos|osx/, "macOS"],
    62→    [/windows.*amd64|amd64.*windows|win64/, "Windows x64"],
    63→    [/windows.*386|win32/, "Windows x86"],
    64→    [/windows/, "Windows"],
    65→  ];
    66→
    67→  // Check if this is a direct binary (archive or executable)
    68→  const isArchive = /\.(tar\.gz|tar\.xz|zip|deb|rpm|dmg|msi|exe|pkg|appimage)(\?|$)/i.test(url);
    69→
    70→  if (isArchive) {
    71→    for (const [pattern, label] of platforms) {
    72→      if (pattern.test(filename) || pattern.test(url)) {
    73→        return { label, isDirect: true };
    74→      }
    75→    }
    76→    // Direct download but platform unknown — use filename
    77→    const cleanName = (url.split("/").pop() ?? "").split("?")[0];
    78→    return { label: cleanName || safeHostname(url), isDirect: true };
    79→  }
    80→
